def _ui_work_bases():
    """Paths to ui_work. PyInstaller uses sys._MEIPASS; Nuitka places data beside the compiled module."""
    bases = []
    meipass = getattr(sys, "_MEIPASS", None)
    if meipass:
        p = os.path.join(meipass, "ui_work")
        if os.path.isdir(p):
            bases.append(p)
    try:
        _mod_dir = os.path.dirname(os.path.abspath(__file__))
        _nu = os.path.join(_mod_dir, "ui_work")
        if os.path.isdir(_nu):
            bases.append(_nu)
    except Exception:
        pass
    bases.append(os.path.join(_HERE, "ui_work"))
    bases.append(os.path.normpath(os.path.join(_HERE, "..", "backend", "ui_work")))
    return bases


def _branding_png_for_path(path_clean: str):
    """Load branding PNG from ui_work/assets (path-specific), then legacy on-disk locations."""
    if path_clean == "/assets/deman.png":
        order = ("deman.png", "deman123.png", "CLS-LOGO.png")
    elif path_clean == "/assets/deman123.png":
        order = ("deman123.png", "CLS-LOGO.png", "deman.png")
    elif path_clean in ("/assets/cls.png", "/assets/cls-logo.png"):
        order = ("cls.png", "CLS-LOGO.png", "deman123.png", "deman.png")
    elif path_clean == "/assets/deman-logo.png":
        order = ("deman-logo.png", "deman.png", "CLS-LOGO.png", "deman123.png")
    else:
        order = ("CLS-LOGO.png", "deman123.png", "deman.png")
    for base in _ui_work_bases():
        adir = os.path.join(base, "assets")
        for name in order:
            p = os.path.normpath(os.path.join(adir, name))
            try:
                if os.path.isfile(p):
                    with open(p, "rb") as f:
                        return f.read()
            except OSError:
                continue
    candidates = []
    meipass = getattr(sys, "_MEIPASS", None)
    if meipass:
        for name in ("deman.png", "deman123.png"):
            candidates.append(os.path.normpath(os.path.join(meipass, name)))
    try:
        _mod_dir = os.path.dirname(os.path.abspath(__file__))
        for name in ("deman.png", "deman123.png"):
            candidates.append(os.path.normpath(os.path.join(_mod_dir, name)))
    except Exception:
        pass
    for rel in (
        "deman.png",
        "deman123.png",
        os.path.join("..", "deman.png"),
        os.path.join("..", "deman123.png"),
    ):
        candidates.append(os.path.normpath(os.path.join(_HERE, rel)))
    for p in candidates:
        try:
            if os.path.isfile(p):
                with open(p, "rb") as f:
                    return f.read()
        except OSError:
            continue
    return None


