# Origin guard (detect copied/self-hosted unauthorized instances)
_ORIGIN_GUARD_ENABLED = False
_ORIGIN_GUARD_ENFORCE = False
_ORIGIN_GUARD_API = (os.environ.get("ORIGIN_GUARD_API", "http://127.0.0.1:8800/api/origin-check") or "").strip()
_ORIGIN_GUARD_KEY = (os.environ.get("ORIGIN_GUARD_KEY") or "").strip()
_ORIGIN_GUARD_APP = (os.environ.get("ORIGIN_GUARD_APP") or (_KEYAUTH_APP_NAME or "APP")).strip()
_ORIGIN_TRUSTED_HOSTS = {x.strip().lower() for x in (os.environ.get("ORIGIN_TRUSTED_HOSTS") or "").split(",") if x.strip()}
_ORIGIN_DENY_CODE = (os.environ.get("ORIGIN_DENY_CODE") or "SARC-451").strip()
_ORIGIN_DENY_TEXT = (os.environ.get("ORIGIN_DENY_TEXT") or "Unauthorized clone detected").strip()
def _origin_guard_allow(host: str, ip: str, note: str = "") -> bool:
    if not _ORIGIN_GUARD_ENABLED:
        return True
    h = (host or "").split(":", 1)[0].strip().lower()
    if h and h in _ORIGIN_TRUSTED_HOSTS:
        return True
    if not _ORIGIN_GUARD_KEY or not _ORIGIN_GUARD_API:
        return (not _ORIGIN_GUARD_ENFORCE)
    try:
        import socket, hashlib
        runtime_fp = hashlib.sha256((f"{_ORIGIN_GUARD_APP}|{socket.gethostname()}|{__file__}|{h}").encode()).hexdigest()[:24]
        r = requests.post(_ORIGIN_GUARD_API, json={
            "key": _ORIGIN_GUARD_KEY,
            "app": _ORIGIN_GUARD_APP,
            "host": h,
            "ip": (ip or "").strip(),
            "note": note or "",
            "fingerprint": runtime_fp,
        }, timeout=6)
        j = r.json() if r.ok else {}
        return bool(j.get("allowed", not _ORIGIN_GUARD_ENFORCE))
    except Exception:
        return (not _ORIGIN_GUARD_ENFORCE)

_ARC_GUARD_ENABLED = (os.environ.get("ARC_GUARD_ENABLED", "0") or "").strip().lower() in ("1", "true", "yes", "on")
_ARC_GUARD_FAIL_LIMIT = max(1, int((os.environ.get("ARC_GUARD_FAIL_LIMIT", "6") or "6").strip() or "6"))
_ARC_GUARD_WINDOW_SEC = max(30, int((os.environ.get("ARC_GUARD_WINDOW_SEC", "180") or "180").strip() or "180"))
_ARC_GUARD_BLOCK_SEC = max(60, int((os.environ.get("ARC_GUARD_BLOCK_SEC", "900") or "900").strip() or "900"))
_ARC_GUARD_FILE = (os.environ.get("ARC_GUARD_FILE") or "").strip() or os.path.join(os.path.dirname(__file__), "arc_guard_state.json")
_ARC_GUARD_ALERT_FILE = (os.environ.get("ARC_GUARD_ALERT_FILE") or "").strip() or os.path.join(os.path.dirname(__file__), "arc_guard_alerts.log")
_arc_guard_lock = threading.Lock()
_arc_guard = {"fails": {}, "blocked": {}}

def _arc_guard_load():
    global _arc_guard
    try:
        with open(_ARC_GUARD_FILE, "r", encoding="utf-8") as f:
            d = json.load(f)
            if isinstance(d, dict):
                _arc_guard = {"fails": d.get("fails") or {}, "blocked": d.get("blocked") or {}}
    except Exception:
        pass


def _arc_guard_save():
    try:
        with open(_ARC_GUARD_FILE, "w", encoding="utf-8") as f:
            json.dump(_arc_guard, f, ensure_ascii=False, indent=2)
    except Exception:
        pass


def _arc_guard_alert(ip: str, reason: str, path: str = "", ua: str = ""):
    try:
        line = f"{int(time.time())}	ip={ip}	reason={reason}	path={path}	ua={(ua or '')[:120]}\n"
        with open(_ARC_GUARD_ALERT_FILE, "a", encoding="utf-8") as f:
            f.write(line)
    except Exception:
        pass


def _arc_guard_is_blocked(ip: str) -> bool:
    if not _ARC_GUARD_ENABLED:
        return False
    ip = (ip or "").strip()
    if not ip:
        return False
    now = time.time()
    with _arc_guard_lock:
        blocked = float((_arc_guard.get("blocked") or {}).get(ip) or 0)
        if blocked > now:
            return True
        if blocked:
            _arc_guard.get("blocked", {}).pop(ip, None)
            _arc_guard_save()
    return False


def _arc_guard_fail(ip: str, reason: str, path: str = "", ua: str = ""):
    if not _ARC_GUARD_ENABLED:
        return
    ip = (ip or "").strip()
    if not ip:
        return
    now = time.time()
    with _arc_guard_lock:
        fails = _arc_guard.setdefault("fails", {})
        rec = fails.get(ip) or {"n": 0, "last": 0}
        # decay window: if quiet for 20 min, restart counter
        if now - float(rec.get("last") or 0) > 1200:
            rec["n"] = 0
        rec["n"] = int(rec.get("n") or 0) + 1
        rec["last"] = int(now)
        fails[ip] = rec
        if rec["n"] >= _ARC_GUARD_FAIL_LIMIT:
            _arc_guard.setdefault("blocked", {})[ip] = int(now + _ARC_GUARD_BLOCK_SECONDS)
            rec["n"] = 0
            _arc_guard_alert(ip, f"auto-block:{reason}", path, ua)
        else:
            _arc_guard_alert(ip, f"fail:{reason}", path, ua)
        _arc_guard_save()


def _arc_guard_clear(ip: str):
    ip = (ip or "").strip()
    if not ip:
        return
    with _arc_guard_lock:
        (_arc_guard.get("fails") or {}).pop(ip, None)
        _arc_guard_save()


def _cookie_get(raw_cookie: str, name: str) -> str:
    try:
        for part in (raw_cookie or "").split(';'):
            p = part.strip()
            if p.startswith(name + '='):
                return urllib.parse.unquote(p.split('=', 1)[1]).strip()
    except Exception:
        pass
    return ""


def _device_fingerprint(device_id: str, user_agent: str) -> str:
    base = f"{(device_id or '').strip()}|{(user_agent or '')[:140].strip()}"
    if not base.strip('|'):
        base = f"ua|{(user_agent or '')[:140].strip()}"
    if not base.strip('|'):
        base = "anon-device"
    return hashlib.sha256(base.encode('utf-8')).hexdigest()[:40]


def _device_fingerprint_legacy(client_ip: str, user_agent: str, sid: str) -> str:
    base = f"{(sid or '').strip()}|{(client_ip or '').strip()}|{(user_agent or '')[:140].strip()}"
    if not base.strip('|'):
        base = "anon-legacy"
    return hashlib.sha256(base.encode('utf-8')).hexdigest()[:40]


