def _parse_epochish(value):
    """Parse KeyAuth-style expiry to unix seconds (UTC)."""
    if value is None:
        return None
    try:
        if isinstance(value, (int, float)):
            iv = int(value)
            if iv > 0:
                return iv
    except Exception:
        pass
    if isinstance(value, str):
        s = value.strip()
        if not s:
            return None
        if s.isdigit():
            try:
                iv = int(s)
                return iv if iv > 0 else None
            except Exception:
                return None
        for fmt in ("%Y-%m-%d %H:%M:%S", "%Y-%m-%d %H:%M:%S.%f", "%Y-%m-%d"):
            try:
                dt = datetime.strptime(s, fmt).replace(tzinfo=timezone.utc)
                return int(dt.timestamp())
            except ValueError:
                continue
        try:
            dt = datetime.fromisoformat(s.replace("Z", "+00:00"))
            if dt.tzinfo is None:
                dt = dt.replace(tzinfo=timezone.utc)
            return int(dt.timestamp())
        except Exception:
            return None
    return None


def _keyauth_apply_expiry_from_client(ka) -> None:
    """Populate _keyauth_license_meta from Keyauth.user after successful license()."""
    global _keyauth_license_meta
    try:
        now = int(time.time())
        best = None
        u = getattr(ka, "user", None)
        if u is None:
            _keyauth_license_meta = {"expires_at": None, "remaining_seconds": None, "checked_at": float(now)}
            return
        subs = getattr(u, "subscriptions", None) or []
        if isinstance(subs, list):
            for sub in subs:
                if isinstance(sub, dict):
                    ep = _parse_epochish(sub.get("expiry"))
                    if ep:
                        best = ep if best is None else max(best, ep)
        if best is None:
            best = _parse_epochish(getattr(u, "expires", None))
        rem = None if best is None else max(0, best - now)
        _keyauth_license_meta = {
            "expires_at": best,
            "remaining_seconds": rem,
            "checked_at": float(now),
        }
    except Exception:
        _keyauth_license_meta = {"expires_at": None, "remaining_seconds": None, "checked_at": float(time.time())}


def _keyauth_resolve_launcher_path(p: str) -> str | None:
    """Resolve argv / Nuitka env path to a real file. Relative names use the EXE directory, not cwd."""
    if not p or not isinstance(p, str):
        return None
    p = p.strip()
    if len(p) >= 2 and p[0] == p[-1] and p[0] in "'\"":
        p = p[1:-1].strip()
    if not p:
        return None
    if os.path.isabs(p):
        try:
            ap = os.path.normpath(os.path.abspath(p))
        except OSError:
            return None
        return ap if os.path.isfile(ap) else None
    if not getattr(sys, "frozen", False) or not sys.executable:
        return None
    exe_dir = os.path.dirname(os.path.abspath(sys.executable))
    joined = os.path.normpath(os.path.join(exe_dir, p))
    return joined if os.path.isfile(joined) else None


def _keyauth_nuitka_outer_exe_path() -> str | None:
    """Nuitka onefile: Python runs from a temp unpack dir; KeyAuth must hash the *outer* EXE the user launched."""
    v = (os.environ.get("NUITKA_ONEFILE_ARGV0") or "").strip()
    if v:
        got = _keyauth_resolve_launcher_path(v)
        if got:
            return got
    try:
        import __compiled__ as _nc  # type: ignore[import-not-found, unused-ignore]

        for attr in ("original_argv0", "onefile_argv0"):
            raw = getattr(_nc, attr, None)
            if isinstance(raw, str) and raw.strip():
                got = _keyauth_resolve_launcher_path(raw.strip())
                if got:
                    return got
    except Exception:
        pass
    return None


def _keyauth_expand_exe_candidate(p: str) -> list[str]:
    """All plausible absolute paths for one argv/executable string."""
    found: list[str] = []
    seen: set[str] = set()

    def push(ap: str) -> None:
        if not ap:
            return
        try:
            n = os.path.normcase(os.path.normpath(os.path.abspath(ap)))
        except OSError:
            return
        if n not in seen:
            seen.add(n)
            found.append(os.path.normpath(os.path.abspath(ap)))

    if not p:
        return found
    r = _keyauth_resolve_launcher_path(p)
    if r:
        push(r)
    try:
        push(os.path.abspath(p))
    except OSError:
        pass
    if getattr(sys, "frozen", False) and sys.executable and not os.path.isabs(p):
        try:
            push(os.path.join(os.path.dirname(os.path.abspath(sys.executable)), p))
        except OSError:
            pass
    return found


def _keyauth_checksum_candidate_paths() -> list[str]:
    """Paths to try for KeyAuth file hash (MD5). Order matters for Nuitka onefile."""
    out: list[str] = []
    seen: set[str] = set()
    frozen = getattr(sys, "frozen", False)

    def push_path(ap: str) -> None:
        if not ap:
            return
        try:
            canon = os.path.normpath(os.path.abspath(ap))
            n = os.path.normcase(canon)
        except OSError:
            return
        if n not in seen and os.path.isfile(canon):
            seen.add(n)
            out.append(canon)

    if frozen:
        nu = _keyauth_nuitka_outer_exe_path()
        if nu:
            push_path(nu)
        if sys.argv:
            for cand in _keyauth_expand_exe_candidate(sys.argv[0]):
                push_path(cand)
        for cand in _keyauth_expand_exe_candidate(sys.executable):
            push_path(cand)
        if sys.platform == "win32":
            try:
                import ctypes

                n = 32768
                buf = ctypes.create_unicode_buffer(n)
                got = ctypes.windll.kernel32.GetModuleFileNameW(None, buf, n)
                if got:
                    push_path(buf.value)
            except Exception:
                pass
    else:
        push_path(__file__)
    return out


def _keyauth_extra_fallback_paths() -> list[str]:
    """Extra paths if discovery missed the real EXE (frozen only)."""
    if not getattr(sys, "frozen", False):
        return []
    out: list[str] = []
    ex = (sys.executable or "").strip()
    if ex:
        try:
            out.append(os.path.normpath(os.path.abspath(ex)))
        except OSError:
            pass
    try:
        up = os.environ.get("USERPROFILE", "").strip()
        if up:
            for tail in (
                r"Desktop\CLS.exe",
                r"OneDrive\Desktop\CLS.exe",
                r"Desktop\DEMAN.exe",
                r"OneDrive\Desktop\DEMAN.exe",
            ):
                p = os.path.normpath(os.path.join(up, tail))
                if os.path.isfile(p):
                    out.append(p)
    except OSError:
        pass
    return out


def _keyauth_embedded_build_md5() -> str:
    """MD5 baked in by two-pass Nuitka build (see build.ps1). Used when hashing the live EXE is unreliable."""
    try:
        from keyauth_embedded import EXE_MD5 as _em
    except ImportError:
        return ""
    if not isinstance(_em, str):
        return ""
    s = _em.strip().strip('"').strip("'")
    if len(s) != 32 or any(c not in "0123456789abcdefABCDEF" for c in s):
        return ""
    return s.lower()


def _keyauth_win32_long_path(path: str) -> str:
    """Prefix with \\?\\ when needed so CreateFileW sees a full Win32 path."""
    ap = os.path.normpath(os.path.abspath(path))
    if ap.startswith("\\\\?\\"):
        return ap
    if len(ap) >= 248:
        return "\\\\?\\" + ap
    return ap


def _keyauth_md5_file_win32_shared(path: str) -> str | None:
    """Read file with full share flags (needed for the running EXE on Windows)."""
    import ctypes
    from ctypes import wintypes

    GENERIC_READ = 0x80000000
    FILE_SHARE_READ = 1
    FILE_SHARE_WRITE = 2
    FILE_SHARE_DELETE = 4
    OPEN_EXISTING = 3
    FILE_ATTRIBUTE_NORMAL = 0x80
    ERROR_HANDLE_EOF = 38

    kernel32 = ctypes.windll.kernel32

    def try_open(p: str):
        return kernel32.CreateFileW(
            p,
            GENERIC_READ,
            FILE_SHARE_READ | FILE_SHARE_WRITE | FILE_SHARE_DELETE,
            None,
            OPEN_EXISTING,
            FILE_ATTRIBUTE_NORMAL,
            None,
        )

    paths_try = [path]
    ext = _keyauth_win32_long_path(path)
    if ext != path:
        paths_try.append(ext)

    h = None
    for p in paths_try:
        h = try_open(p)
        if h is not None and h != wintypes.HANDLE(-1).value and h != 0xFFFFFFFFFFFFFFFF:
            break
    if h is None or h == wintypes.HANDLE(-1).value or h == 0xFFFFFFFFFFFFFFFF:
        return None

    md5_hash = hashlib.md5()
    bufsize = 1 << 20
    buf = (ctypes.c_char * bufsize)()
    try:
        while True:
            read = wintypes.DWORD(0)
            ok = kernel32.ReadFile(h, buf, bufsize, ctypes.byref(read), None)
            n = int(read.value)
            if ok and n == 0:
                break
            if not ok:
                err = kernel32.GetLastError()
                if n == 0 and err == ERROR_HANDLE_EOF:
                    break
                if n == 0:
                    break
                return None
            md5_hash.update(buf.raw[:n])
        return md5_hash.hexdigest()
    finally:
        kernel32.CloseHandle(h)


def _keyauth_md5_certutil(path: str) -> str | None:
    """Out-of-process MD5 via certutil — often works when the running EXE cannot be opened from Python."""
    if sys.platform != "win32":
        return None
    import re

    try:
        cr = getattr(subprocess, "CREATE_NO_WINDOW", 0)
        sys_root = os.environ.get("SystemRoot", r"C:\Windows")
        certutil = os.path.join(sys_root, "System32", "certutil.exe")
        cmd = [certutil, "-hashfile", path, "MD5"] if os.path.isfile(certutil) else ["certutil", "-hashfile", path, "MD5"]
        r = subprocess.run(
            cmd,
            capture_output=True,
            text=True,
            timeout=120,
            creationflags=cr,
            check=False,
        )
        if r.returncode != 0:
            return None
        for line in (r.stdout or "").splitlines():
            m = re.search(r"([0-9A-Fa-f]{32})", line)
            if m:
                return m.group(1).lower()
    except Exception:
        return None
    return None


def _keyauth_md5_powershell(path: str) -> str | None:
    """Fallback: PowerShell Get-FileHash (another process reading the file)."""
    if sys.platform != "win32":
        return None
    import json
    import re

    try:
        cr = getattr(subprocess, "CREATE_NO_WINDOW", 0)
        ps = f"(Get-FileHash -LiteralPath {json.dumps(path)} -Algorithm MD5).Hash"
        sys_root = os.environ.get("SystemRoot", r"C:\Windows")
        psh = os.path.join(sys_root, "System32", "WindowsPowerShell", "v1.0", "powershell.exe")
        ps_cmd = [psh, "-NoProfile", "-NoLogo", "-Command", ps] if os.path.isfile(psh) else ["powershell", "-NoProfile", "-NoLogo", "-Command", ps]
        r = subprocess.run(
            ps_cmd,
            capture_output=True,
            text=True,
            timeout=120,
            creationflags=cr,
            check=False,
        )
        if r.returncode != 0:
            return None
        m = re.search(r"([0-9A-Fa-f]{32})", (r.stdout or "").strip())
        if m:
            return m.group(1).lower()
    except Exception:
        return None
    return None


def _keyauth_checksum() -> str:
    """MD5 for KeyAuth init: env override, then Nuitka-embedded build hash, else hash proxy.py / runtime EXE."""
    ev = (os.environ.get("KEYAUTH_EXE_MD5") or "").strip().lower()
    if len(ev) == 32 and all(c in "0123456789abcdef" for c in ev):
        return ev
    emb = _keyauth_embedded_build_md5()
    if emb:
        return emb

    paths = list(_keyauth_checksum_candidate_paths())
    for p in _keyauth_extra_fallback_paths():
        if p and p not in paths:
            paths.append(p)

    for path in paths:
        try:
            md5_hash = hashlib.md5()
            with open(path, "rb") as f:
                while True:
                    block = f.read(65536)
                    if not block:
                        break
                    md5_hash.update(block)
            return md5_hash.hexdigest()
        except OSError:
            pass
        if sys.platform == "win32":
            alt = _keyauth_md5_file_win32_shared(path)
            if alt:
                return alt
            cu = _keyauth_md5_certutil(path)
            if cu:
                return cu
            ps = _keyauth_md5_powershell(path)
            if ps:
                return ps
    return ""


def _read_keyauth_license_file() -> str:
    try:
        if os.path.isfile(KEYAUTH_LICENSE_FILE):
            with open(KEYAUTH_LICENSE_FILE, "r", encoding="utf-8") as f:
                return (f.read() or "").strip()
    except OSError:
        pass
    return ""


def _verify_keyauth_license(license_key: str, *, skip_internal: bool = False) -> tuple[bool, str, str]:
    """Returns (ok, error_message, customer_panel_url).

    If skip_internal is True, only the KeyAuth cloud path runs (after internal activate was already attempted elsewhere).
    """
    global _keyauth_license_meta
    license_key = (license_key or "").strip()
    if not license_key:
        return False, "Empty license key", _KEYAUTH_PANEL
    # Keep HWID stable across restarts/updates to avoid forcing new key each time.
    h = (os.environ.get("KEYAUTH_HWID_OVERRIDE") or "").strip()
    if not h:
        h = f"{(_KEYAUTH_APP_NAME or 'app').lower()}-web-hwid-stable-2026"
    if len(h) < 20:
        h = (h + "-stable-hwid-2026-xxxxxxxxxxxxxxxx")[:32]
    if not h:
        return False, "Could not compute application checksum", _KEYAUTH_PANEL

    # Internal license engine (optional). If the key is not valid here, try KeyAuth.
    if (
        (not skip_internal)
        and _INTERNAL_LICENSE_ENABLED
        and _lic_core is not None
    ):
        try:
            tenant = (_KEYAUTH_APP_NAME or "DEMAN").strip().upper()
            ok_i, msg_i = _lic_core.validate_license(tenant=tenant, license_key=license_key, device_id=h, user_id="")
            if ok_i:
                return True, "", "https://discord.gg/deman"
            ok_a, msg_a = _lic_core.activate_license(tenant=tenant, license_key=license_key, device_id=h, user_id="")
            if ok_a:
                return True, "", "https://discord.gg/deman"
        except Exception as e:
            return False, str(e or "Internal license verify failed"), _KEYAUTH_PANEL

    # KeyAuth cloud verification path (platform-issued licenses)
    try:
        app = (_KEYAUTH_APP_NAME or "").strip()
        owner = (_KEYAUTH_OWNER_ID or "").strip()
        ver = (_KEYAUTH_APP_VERSION or "1.0").strip()
        if not (app and owner):
            return False, "KeyAuth config missing (name / ownerid)", _KEYAUTH_PANEL

        # Application file MD5 (same role as KeyAuth Python api(..., hash_to_check=getchecksum())).
        # Dashboard "application hash" / hash-check must match, or disable hash check in KeyAuth.
        # Override: KEYAUTH_EXE_MD5 / embedded EXE_MD5; web-only dev may set KEYAUTH_EXE_MD5 to the hash you registered.
        ka_hash = _keyauth_checksum()
        hash_attempts = [ka_hash, ""] if ka_hash else [""]

        last_err = "KeyAuth init failed"
        sessionid = ""
        api_url = ""
        for ka_h in hash_attempts:
            enckey = secrets.token_hex(12)[:35]
            init_payload = {
                "type": "init",
                "name": app,
                "ownerid": owner,
                "ver": ver,
                "hash": ka_h,
                "enckey": enckey,
            }
            for base in _keyauth_api_urls():
                try:
                    ri = requests.post(base, data=init_payload, timeout=12)
                    ji = _keyauth_response_json(ri)
                    if ji.get("success"):
                        sid = (ji.get("sessionid") or "").strip()
                        if sid:
                            sessionid = sid
                            api_url = base
                            break
                    last_err = str(ji.get("message") or "KeyAuth init failed")
                except Exception as ex:
                    last_err = str(ex or "KeyAuth init failed")
            if sessionid:
                break
        if not sessionid:
            return False, last_err, _KEYAUTH_PANEL

        lic_payload = {
            "type": "license",
            "name": app,
            "ownerid": owner,
            "sessionid": sessionid,
            "key": license_key,
            "hwid": h,
        }
        rl = requests.post(api_url, data=lic_payload, timeout=12)
        jl = _keyauth_response_json(rl)
        if jl.get("success"):
            return True, "", _KEYAUTH_PANEL
        return False, str(jl.get("message") or "Invalid license key"), _KEYAUTH_PANEL
    except Exception as e:
        return False, str(e or "License backend unavailable"), _KEYAUTH_PANEL


def _refresh_keyauth_cache_from_disk() -> None:
    if not KEYAUTH_REQUIRED:
        return
    lic = _read_keyauth_license_file()
    with _keyauth_cache_lock:
        if lic == _keyauth_cache.get("file_lic"):
            return
    if not lic:
        with _keyauth_cache_lock:
            _keyauth_cache["file_lic"] = ""
            _keyauth_cache["ok"] = False
            _keyauth_cache["last_error"] = ""
        global _keyauth_license_meta
        _keyauth_license_meta = {"expires_at": None, "remaining_seconds": None, "checked_at": float(time.time())}
        return
    ok, err, panel = _verify_keyauth_license(lic)
    with _keyauth_cache_lock:
        _keyauth_cache["file_lic"] = lic
        _keyauth_cache["ok"] = ok
        if panel:
            _keyauth_cache["panel"] = panel
        _keyauth_cache["last_error"] = err if not ok else ""


def ensure_keyauth() -> bool:
    """True if KeyAuth is disabled, or a valid license is on disk for this machine."""
    if not KEYAUTH_REQUIRED:
        return True
    _refresh_keyauth_cache_from_disk()
    with _keyauth_cache_lock:
        return bool(_keyauth_cache.get("ok"))


def _keyauth_clear_saved_license_on_startup() -> None:
    """Always clear saved license at startup so every new app run asks for key again."""
    if not KEYAUTH_REQUIRED:
        return
    try:
        if os.path.isfile(KEYAUTH_LICENSE_FILE):
            os.remove(KEYAUTH_LICENSE_FILE)
    except OSError:
        pass
    global _keyauth_bound_ip
    with _keyauth_cache_lock:
        _keyauth_cache["file_lic"] = ""
        _keyauth_cache["ok"] = False
        _keyauth_cache["last_error"] = ""
        _keyauth_bound_ip = ""


