def _configure_stdio_utf8():
    if sys.platform != "win32":
        return
    for stream in (sys.stdout, sys.stderr):
        if stream is not None and hasattr(stream, "reconfigure"):
            try:
                stream.reconfigure(encoding="utf-8", errors="replace")
            except Exception:
                pass


def _log(*args, **kwargs):
    if getattr(sys, "frozen", False) and os.environ.get("ARC_DEBUG", "") != "1":
        return
    builtins.print(*args, **kwargs)


_SILENT_STDOUT = None
_SILENT_STDERR = None


def _discard_stdio_if_frozen_exe() -> None:
    """Keep console window open (PyInstaller console=True) but send all output to nowhere."""
    global _SILENT_STDOUT, _SILENT_STDERR
    if not getattr(sys, "frozen", False):
        return
    if os.environ.get("ARC_DEBUG", "") == "1":
        return
    if _SILENT_STDOUT is not None:
        return
    try:
        _SILENT_STDOUT = open(os.devnull, "w", encoding="utf-8", errors="replace")
        _SILENT_STDERR = open(os.devnull, "w", encoding="utf-8", errors="replace")
        sys.stdout = _SILENT_STDOUT
        sys.stderr = _SILENT_STDERR
    except Exception:
        pass


def _fatal_frozen_ui(message: str, exc: BaseException | None = None) -> None:
    """When running as EXE, show error in a file + Windows message box (not on console)."""
    import traceback

    log_path = os.path.join(_app_dir(), "arc_proxy_error.log")
    try:
        with open(log_path, "w", encoding="utf-8") as f:
            f.write(message + "\n\n")
            if exc is not None:
                traceback.print_exception(type(exc), exc, exc.__traceback__, file=f)
    except Exception:
        log_path = "(could not write log file)"

    try:
        import ctypes

        ctypes.windll.user32.MessageBoxW(
            0,
            f"{message}\n\nDetails saved to:\n{log_path}",
            "DEMAN.SOTRE Proxy",
            0x00000010,
        )
    except Exception:
        pass


