def _detect_browsers() -> list:
    """Return list of dicts {name, path} for every browser exe found on disk."""
    found = [{"name": "Default Browser", "path": ""}]
    seen: set = set()
    for name, paths in _BROWSER_CANDIDATES:
        for p in paths:
            if p and os.path.isfile(p) and p not in seen:
                found.append({"name": name, "path": p})
                seen.add(p)
                break
    return found


def _load_browser_pref() -> str:
    """Return saved browser exe path, or '' for system default."""
    try:
        if os.path.isfile(BROWSER_PREF_FILE):
            p = open(BROWSER_PREF_FILE, "r", encoding="utf-8").read().strip()
            if not p or os.path.isfile(p):
                return p
    except Exception:
        pass
    return ""


def _save_browser_pref(path: str) -> None:
    try:
        with open(BROWSER_PREF_FILE, "w", encoding="utf-8") as f:
            f.write(path)
    except Exception as e:
        _log(f"Could not save browser pref: {e}")


def _maybe_open_browser() -> None:
    """Open the tool URL in the user-selected (or system default) browser."""
    if os.environ.get("ARC_NO_BROWSER", "") == "1" or os.environ.get("RENDER"):
        return

    url = f"http://localhost:{PORT}"
    pref = _load_browser_pref()

    def _run():
        time.sleep(0.65)
        try:
            if pref and os.path.isfile(pref):
                subprocess.Popen([pref, url],
                                 creationflags=getattr(subprocess, "CREATE_NO_WINDOW", 0))
            elif sys.platform == "win32":
                os.startfile(url)
            else:
                import webbrowser
                webbrowser.open(url)
        except Exception:
            try:
                import webbrowser
                webbrowser.open(url)
            except Exception:
                pass

    threading.Thread(target=_run, daemon=True).start()

