    def handle_admin_keygen(self):
        """Admin-only: generate INTERNAL licenses (KeyAuth removed)."""
        try:
            auth = (self.headers.get("Authorization") or "").strip()
            if (not KEYGEN_ADMIN_TOKEN) or auth != f"Bearer {KEYGEN_ADMIN_TOKEN}":
                self._json_error(403, "Forbidden")
                return
            if _lic_core is None:
                self._json_error(503, "Internal license service unavailable")
                return
            length = int(self.headers.get("Content-Length", 0))
            raw = self.rfile.read(length).decode("utf-8") if length else "{}"
            body = json.loads(raw) if raw.strip() else {}
            count = int(body.get("count", 1) or 1)
            tenant = str(body.get("tenant") or _KEYAUTH_APP_NAME or "DEMAN").strip().upper()
            if count < 1 or count > 200:
                self._json_error(400, "count must be between 1 and 200")
                return
            keys = _lic_core.create_keys(tenant=tenant, count=count, actor="admin-api")
            self._json_ok(json.dumps({"ok": True, "tenant": tenant, "count": len(keys), "keys": keys}).encode("utf-8"))
        except Exception as e:
            self._json_error(500, str(e))

    def handle_clear_token(self):
        """Logout current token + force re-license on next login."""
        global API_TOKEN, _keyauth_bound_ip
        try:
            API_TOKEN = None
            try:
                if os.path.isfile(TOKEN_FILE):
                    os.remove(TOKEN_FILE)
            except OSError:
                pass

            # Also clear license so next login always asks key again.
            try:
                if os.path.isfile(KEYAUTH_LICENSE_FILE):
                    os.remove(KEYAUTH_LICENSE_FILE)
            except OSError:
                pass
            with _keyauth_cache_lock:
                _keyauth_cache["file_lic"] = ""
                _keyauth_cache["ok"] = False
                _keyauth_cache["last_error"] = ""
                _keyauth_bound_ip = ""

            self._json_ok(json.dumps({"ok": True}).encode("utf-8"))
            _log("✅ Token cleared via /api/clear-token")
        except Exception as e:
            self._json_error(500, str(e))

