    def handle_set_browser(self):
        """Save browser preference. Body: { "path": "C:\\...\\chrome.exe" } or "" for default."""
        try:
            length = int(self.headers.get("Content-Length", 0))
            raw  = self.rfile.read(length).decode("utf-8") if length else "{}"
            body = json.loads(raw) if raw.strip() else {}
            path = (body.get("path") or "").strip()
            if path and not os.path.isfile(path):
                self._json_error(400, "Browser executable not found")
                return
            _save_browser_pref(path)
            self._json_ok(json.dumps({"ok": True, "path": path}).encode("utf-8"))
            _log(f"✅ Browser preference saved: {path or 'system default'}")
        except Exception as e:
            self._json_error(400, str(e))

    # ── Inventory ──────────────────────────────────────────────────────────────

    def handle_inventory(self):
        user_token = _extract_user_token(self.headers)
        try:
            if not user_token:
                if not ensure_token():
                    self._json_error(401, "Authentication required")
                    return
            auth_token = user_token or API_TOKEN

            _log("📦 Fetching inventory (stash + backpack)...")
            merged = get_inventory(auth_token)
            self._json_ok(
                json.dumps(merged, default=str, ensure_ascii=False).encode("utf-8")
            )
            _log(f"✅ Inventory fetched: {len(merged.get('items', []))} items")

        except Exception as e:
            err = str(e)
            _log(f"❌ Inventory error: {err}")
            el = err.lower()
            embark_unauthorized = "status 401" in el or "status 403" in el
            if embark_unauthorized:
                if AUTO_OAUTH and not user_token:
                    _log("❌ Token expired. Refreshing...")
                    if get_new_token():
                        self.handle_inventory()
                        return
                self._json_error(
                    401, "Authentication failed — token expired or invalid (Embark rejected the request)"
                )
                return
            self._json_error(500, err)

    def handle_session(self):
        """Profile + non-sensitive JWT hints for the signed-in account (Embark API)."""
        user_token = _extract_user_token(self.headers)
        try:
            if not user_token:
                if not ensure_token():
                    self.send_error(401, "Authentication required")
                    return
            auth_token = user_token or API_TOKEN
            out: dict = {"profile": None, "tokenHints": None, "level": None, "errors": []}
            hints = _session_token_hints(auth_token)
            if hints:
                out["tokenHints"] = hints
            try:
                out["profile"] = get_profile(auth_token)
            except Exception as e:
                _log(f"⚠️ Profile fetch: {e}")
                out["errors"].append({"source": "profile", "message": str(e)})
            try:
                lv_raw = get_levels_list(auth_token)
                out["level"] = _extract_player_level(lv_raw)
            except Exception as e:
                _log(f"⚠️ Levels fetch: {e}")
                out["errors"].append({"source": "levels", "message": str(e)})
            self._json_ok(json.dumps(out, default=str).encode("utf-8"))
        except Exception as e:
            _log(f"❌ Session error: {e}")
            err = str(e)
            if "401" in err or "403" in err or "status 40" in err:
                self.send_error(401, 'Authentication failed — token expired or invalid')
            else:
                self.send_error(500, err)

